// recursion
function sum(n) {
  if (n === 0) return 0;
  return n + sum(n - 1);
}
console.log(sum(10));

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)
print(factorial(5))

public static int fibonacci(int n) {
    if (n <= 1) return n;
    return fibonacci(n - 1) + fibonacci(n - 2);
}
int result = fibonacci(7);

WITH RECURSIVE numbers AS (
  SELECT 1 AS n
  UNION ALL
  SELECT n + 1 FROM numbers WHERE n < 5
) SELECT * FROM numbers;
